// =============================================================
// Update Response Handler — PATCH responses row with field_mapping
// =============================================================
// Reads variableContext.responseId and currentStep.step_config.field_mapping.
// Resolves source_expression against variableContext (simple {{stepId.fieldKey}} pattern).
// PATCHes responses table via Supabase REST.
// JSONB columns (ai_qualification): pass object directly — NEVER JSON.stringify (double-encode bug).
// tenant_id filter on all Supabase queries for security.
// =============================================================

const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
if (!SUPABASE_URL) throw new Error('SUPABASE_URL not configured');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// Simple {{key}} and {{nested.key}} variable resolver against variableContext
function resolveExpression(expression, context) {
  if (typeof expression !== 'string') return expression;
  // Handle {{variable}} pattern
  const match = expression.match(/^\{\{\s*([\w.]+)\s*\}\}$/);
  if (match) {
    const key = match[1].trim();
    // Support nested paths like stepId.fieldKey
    const parts = key.split('.');
    let value = context;
    for (const part of parts) {
      if (value === null || value === undefined || typeof value !== 'object') return expression;
      value = value[part];
    }
    return value !== undefined ? value : expression;
  }
  // Plain string (no template) — return as-is
  return expression;
}

async function supabasePatch(path, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const match = url.match(/^https?:\/\/([^/]+)(\/.*)$/);
    if (!match) { reject(new Error('Invalid SUPABASE_URL')); return; }
    const bodyStr = JSON.stringify(body);
    const options = {
      hostname: match[1],
      path: match[2],
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(bodyStr),
        'Prefer': 'return=minimal',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase PATCH ${path}: ${res.statusCode} ${data}`));
        } else {
          resolve(true);
        }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

try {
  const item = $input.first().json;
  const { variableContext, currentStep, tenantId } = item;

  // Validate required input
  const responseId = variableContext.responseId;
  if (!responseId) throw new Error('update_response requires variableContext.responseId');

  const fieldMapping = (currentStep && currentStep.step_config && currentStep.step_config.field_mapping) || [];
  if (!Array.isArray(fieldMapping) || fieldMapping.length === 0) {
    // No mappings configured — succeed with no-op
    return {
      json: {
        ...item,
        stepResult: {
          success: true,
          outputPayload: { updated: true, updatedAt: new Date().toISOString() },
        },
      }
    };
  }

  const safeTenantId = tenantId ?? '00000000-0000-0000-0000-000000000000';

  // Build PATCH body from resolved field_mapping
  const patchBody = {};
  for (const mapping of fieldMapping) {
    const { target_column, source_expression } = mapping;
    if (!target_column) continue;
    const resolved = resolveExpression(source_expression, variableContext);
    // JSONB columns: pass object directly — never JSON.stringify (double-encode bug)
    patchBody[target_column] = resolved;
  }

  // PATCH responses with tenant_id filter for security
  await supabasePatch(
    `responses?id=eq.${responseId}&tenant_id=eq.${encodeURIComponent(safeTenantId)}`,
    patchBody
  );

  return {
    json: {
      ...item,
      stepResult: {
        success: true,
        outputPayload: { updated: true, updatedAt: new Date().toISOString() },
      },
    }
  };
} catch (err) {
  const item = $input.first().json;
  return { json: { ...item, stepResult: { success: false, error: err.message } } };
}
